      text: 'text-orange-600',
      fill: '#f97316'
    },
    black: { // TikTok
      border: 'border-gray-200',
      bg: 'bg-white',
      header: 'bg-gray-900',
      text: 'text-gray-900',
      fill: '#111827'
    },
    yellow: { // Mercado Livre
      border: 'border-yellow-200',
      bg: 'bg-white',
      header: 'bg-yellow-400',
      text: 'text-yellow-700', // Darker text for readability
      fill: '#facc15'
    },
    blue: { // Amazon
      border: 'border-slate-200',
      bg: 'bg-white',
      header: 'bg-slate-800',
      text: 'text-slate-800',
      fill: '#1e293b'
    }
  };

  const currentTheme = themeClasses[colorTheme];

  // Calculate total money paid to the platform
  const totalFees = result.totalVariableCosts + 
                    result.feesBreakdown.fixedFee + 
                    (result.feesBreakdown.tax || 0) + 
                    (result.feesBreakdown.affiliate || 0);

  // Calculate total cost (Product + Oper + All Fees)
  const totalProdOper = result.totalFixedCosts - result.feesBreakdown.fixedFee;
  const totalSaleCost = totalProdOper + totalFees;

  const chartData = [
    { name: 'Custo Fixo (Prod + Oper)', value: totalProdOper, color: '#9CA3AF' },
    { name: 'Taxas & Comissões', value: totalFees, color: '#EF4444' },
    { name: 'Lucro Líquido', value: result.netProfit > 0 ? result.netProfit : 0, color: '#10B981' },
  ];

  // Custom text color for ML header because yellow background is light
  const headerTextColor = colorTheme === 'yellow' ? 'text-gray-900' : 'text-white';

  // Clean platform name for display
  const displayName = result.platformName
    .replace(' (Clássico)', '')
    .replace(' (Premium)', '')
    .replace(' (Sem Frete Grátis)', '')
    .replace(' (Com Frete Grátis)', '');

  return (
    <div className={`rounded-xl shadow-lg overflow-hidden border ${currentTheme.border} ${currentTheme.bg} flex flex-col`}>
      <div className={`${currentTheme.header} ${headerTextColor} p-4 flex justify-between items-center`}>
        <h3 className="font-bold text-lg">{displayName}</h3>
        <span className={`text-xs px-2 py-1 rounded backdrop-blur-sm ${colorTheme === 'yellow' ? 'bg-black/10' : 'bg-white/20'}`}>
           {result.feesBreakdown.affiliate && result.feesBreakdown.affiliate > 0 ? 'Com Afiliado' : 'Padrão'}
        </span>
      </div>

      <div className="p-6 flex-1 flex flex-col">

        {/* Mercado Livre Toggle Section */}
        {colorTheme === 'yellow' && mlListingType && onMlListingTypeChange && (
            <div className="mb-6">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block">
                   Tipo de Anúncio
                 </label>
                 <div className="flex p-1 bg-yellow-50 border border-yellow-200 rounded-lg shadow-inner">
                    <button
                       onClick={() => onMlListingTypeChange('classic')}
                       className={`flex-1 py-1.5 text-xs font-bold rounded uppercase tracking-wide transition-all ${
                         mlListingType === 'classic'
                           ? 'bg-yellow-400 text-yellow-900 shadow-sm'
                           : 'text-yellow-600 hover:text-yellow-800'
                       }`}
                    >
                      Clássico
                    </button>
                    <button
                       onClick={() => onMlListingTypeChange('premium')}
                       className={`flex-1 py-1.5 text-xs font-bold rounded uppercase tracking-wide transition-all ${
                         mlListingType === 'premium'
                           ? 'bg-yellow-400 text-yellow-900 shadow-sm'
                           : 'text-yellow-600 hover:text-yellow-800'
                       }`}
                    >
                      Premium
                    </button>
                 </div>
                 <p className="text-[10px] text-gray-500 mt-1.5 text-center px-1">
                   {mlListingType === 'classic' 
                     ? 'Exposição alta e duração ilimitada.' 
                     : 'Exposição máxima e parcelamento sem juros.'}
                 </p>
            </div>
        )}

        {/* Shopee Toggle Section */}
        {colorTheme === 'orange' && shopeeListingType && onShopeeListingTypeChange && (
            <div className="mb-6">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block">
                   Programa Frete Grátis
                 </label>
                 <div className="flex p-1 bg-orange-50 border border-orange-200 rounded-lg shadow-inner">
                    <button
                       onClick={() => onShopeeListingTypeChange('standard')}
                       className={`flex-1 py-1.5 text-xs font-bold rounded uppercase tracking-wide transition-all ${
                         shopeeListingType === 'standard'
                           ? 'bg-[#ee4d2d] text-white shadow-sm'
                           : 'text-orange-600 hover:text-orange-800 hover:bg-orange-100'
                       }`}
                    >
                      Sem Frete Grátis
                    </button>
                    <button
                       onClick={() => onShopeeListingTypeChange('free_shipping')}
                       className={`flex-1 py-1.5 text-xs font-bold rounded uppercase tracking-wide transition-all ${
                         shopeeListingType === 'free_shipping'
                           ? 'bg-[#ee4d2d] text-white shadow-sm'
                           : 'text-orange-600 hover:text-orange-800 hover:bg-orange-100'
                       }`}
                    >
                      Com Frete Grátis
                    </button>
                 </div>
                 <p className="text-[10px] text-gray-500 mt-1.5 text-center px-1">
                   {shopeeListingType === 'standard' 
                     ? 'Comissão padrão (aprox. 14%). Sem selo destaque.' 
                     : 'Comissão maior (aprox. 20%). Selo de Frete Grátis.'}
                 </p>
            </div>
        )}

        <div className="mb-6 text-center">
          <p className="text-sm text-gray-500 mb-1">Preço de Venda Final</p>
          <div className={`text-4xl font-bold ${currentTheme.text}`}>
            {formatCurrency(result.sellingPrice)}
          </div>
        </div>

        {/* Reverted Grid to 2 columns */}
        <div className="grid grid-cols-2 gap-4 mb-6">
           <div className="bg-emerald-50 p-3 rounded-lg border border-emerald-100 text-center">
              <p className="text-xs text-emerald-700 font-medium uppercase tracking-wide mb-1">Lucro (R$)</p>
              <p className="text-2xl font-bold text-emerald-600">{formatCurrency(result.netProfit)}</p>
           </div>
           <div className="bg-emerald-50 p-3 rounded-lg border border-emerald-100 text-center">
              <p className="text-xs text-emerald-700 font-medium uppercase tracking-wide mb-1">Margem</p>
              <p className="text-2xl font-bold text-emerald-600">{formatPercent(result.netProfitMargin)}</p>
           </div>
        </div>

        <div className="mb-6 h-32 w-full relative">
           <ResponsiveContainer width="100%" height="100%">
             <PieChart>
               <Pie
                 data={chartData}
                 cx="50%"
                 cy="50%"
                 innerRadius={40}
                 outerRadius={60}
                 paddingAngle={2}
                 dataKey="value"
               >
                 {chartData.map((entry, index) => (
                   <Cell key={`cell-${index}`} fill={entry.color} />
                 ))}
               </Pie>
               <Tooltip formatter={(value: number) => formatCurrency(value)} />
             </PieChart>
           </ResponsiveContainer>
           <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
             <span className="text-xs text-gray-400 font-medium">Detalhamento</span>
           </div>
        </div>

        <div className="space-y-2 text-sm border-t border-gray-100 pt-4 mt-auto">
          <div className="flex justify-between">
            <span className="text-gray-500">Custo Fixo Total (Prod+Op):</span>
            <span className="font-medium text-gray-700">{formatCurrency(totalProdOper)}</span>
          </div>
          <div className="flex justify-between">
             <span className="text-gray-500">Comissão:</span>
             <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.commission)}</span>
          </div>
           {result.feesBreakdown.transactionFee > 0 && (
            <div className="flex justify-between">
              <span className="text-gray-500">Taxa Transação:</span>
              <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.transactionFee)}</span>
            </div>
          )}
          {result.feesBreakdown.affiliate && result.feesBreakdown.affiliate > 0 && (
             <div className="flex justify-between">
               <span className="text-gray-500">Afiliado:</span>
               <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.affiliate)}</span>
             </div>
          )}
           <div className="flex justify-between">
              <span className="text-gray-500">Taxa Fixa Item:</span>
              <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.fixedFee)}</span>
            </div>

            <div className="flex justify-between font-semibold bg-gray-50 rounded px-2 py-1 -mx-2">
               <span className="text-gray-700">Taxas e Encargos Total:</span>
               <span className="text-red-600">-{formatCurrency(totalFees)}</span>
            </div>

           {result.feesBreakdown.tax > 0 && (
             <div className="flex justify-between">
                <span className="text-gray-500">Imposto:</span>
                <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.tax)}</span>
              </div>
           )}

           <div className="flex justify-between font-bold text-gray-800 pt-2 border-t border-gray-100 mt-2">
              <span>Custo Total da Venda:</span>
              <span>-{formatCurrency(totalSaleCost)}</span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default ResultCard;

import React from 'react';
import { UserInputs, CalculationMethod } from '../types';

interface CalculatorInputsProps {
  inputs: UserInputs;
  setInputs: React.Dispatch<React.SetStateAction<UserInputs>>;
  method: CalculationMethod;
  setMethod: (m: CalculationMethod) => void;
}

const CalculatorInputs: React.FC<CalculatorInputsProps> = ({ inputs, setInputs, method, setMethod }) => {

  // Allow string or number value to be set directly
  const handleChange = (field: keyof UserInputs, value: string | boolean) => {
    setInputs(prev => ({ ...prev, [field]: value }));
  };

  const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
    e.target.select();
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>, nextFieldId?: string) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      if (nextFieldId) {
        const nextElement = document.getElementById(nextFieldId);
        if (nextElement) {
          nextElement.focus();
        }
      } else {
        // Se for o último campo, remove o foco (útil para fechar teclado mobile)
        e.currentTarget.blur();
      }
    }
  };

  const handleClear = () => {
    setInputs({
      productCost: '',
      operationalCost: '',
      targetMargin: '',
      testPrice: '',
      isCNPJ: false,
      taxRate: '',
      mlListingType: 'classic',
      shopeeListingType: 'free_shipping',
    });
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 h-full flex flex-col">
      <div className="mb-6">
        <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Método de Cálculo</label>
        <div className="mt-2 flex p-1 bg-gray-100 rounded-lg">
          <button
            onClick={() => setMethod(CalculationMethod.TARGET_MARGIN)}
            className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
              method === CalculationMethod.TARGET_MARGIN
                ? 'bg-white text-indigo-600 shadow-sm'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            🎯 Margem Alvo
          </button>
          <button
            onClick={() => setMethod(CalculationMethod.REAL_PROFIT)}
            className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
              method === CalculationMethod.REAL_PROFIT
                ? 'bg-white text-emerald-600 shadow-sm'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            💰 Lucro Real
          </button>
        </div>
      </div>

      <div className="mb-6 bg-gray-50 rounded-lg p-3 border border-gray-200 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className={`p-1.5 rounded-md ${inputs.isCNPJ ? 'bg-blue-100 text-blue-600' : 'bg-gray-200 text-gray-500'}`}>
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
                <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 21h16.5M4.5 3h15M5.25 3v18m13.5-18v18M9 6.75h1.5m-1.5 3h1.5m-1.5 3h1.5m3-6H15m-1.5 3H15m-1.5 3H15M9 21v-3.375c0-.621.504-1.125 1.125-1.125h3.75c.621 0 1.125.504 1.125 1.125V21" />
              </svg>
            </div>
            <div>
              <span className="text-sm font-bold text-gray-800 block">Sou CNPJ</span>
              <span className="text-xs text-gray-500">Habilitar cálculo de impostos</span>
            </div>
          </div>
          <button 
            onClick={() => handleChange('isCNPJ', !inputs.isCNPJ)}
            className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none ${inputs.isCNPJ ? 'bg-blue-600' : 'bg-gray-200'}`}
          >
            <span
              className={`pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${inputs.isCNPJ ? 'translate-x-5' : 'translate-x-0'}`}
            />
          </button>
      </div>

      <div className="space-y-5 flex-1">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Custo do Produto (R$)</label>
            <input
              id="productCost"
              type="number"
              inputMode="decimal"
              min="0"
              step="0.01"
              placeholder="0.00"
              value={inputs.productCost}
              onFocus={handleFocus}
              onChange={(e) => handleChange('productCost', e.target.value)}
              onKeyDown={(e) => handleKeyDown(e, 'operationalCost')}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all bg-white text-gray-900 placeholder-gray-300"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Custo Operacional (R$)</label>
            <input
              id="operationalCost"
              type="number"
              inputMode="decimal"
              min="0"
              step="0.01"
              placeholder="0.00"
              value={inputs.operationalCost}
              onFocus={handleFocus}
              onChange={(e) => handleChange('operationalCost', e.target.value)}
              onKeyDown={(e) => handleKeyDown(e, inputs.isCNPJ ? 'taxRate' : (method === CalculationMethod.TARGET_MARGIN ? 'targetMargin' : 'testPrice'))}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all bg-white text-gray-900 placeholder-gray-300"
            />
          </div>
        </div>

        {inputs.isCNPJ && (
          <div className="bg-blue-50/50 p-4 rounded-lg border border-blue-100">
             <label className="block text-sm font-bold text-gray-700 mb-1">Imposto Federal - DAS/Simples (%)</label>
             <div className="relative">
                <input
                  id="taxRate"
                  type="number"
                  inputMode="decimal"
                  min="0"
                  max="100"
                  step="0.1"
                  placeholder="Ex: 4.0"
                  value={inputs.taxRate}
                  onFocus={handleFocus}
                  onChange={(e) => handleChange('taxRate', e.target.value)}
                  onKeyDown={(e) => handleKeyDown(e, method === CalculationMethod.TARGET_MARGIN ? 'targetMargin' : 'testPrice')}
                  className="w-full pl-3 pr-8 py-2 border border-blue-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all bg-white text-gray-900 placeholder-gray-400"
                />
                <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 font-medium">%</span>
             </div>
             <span className="text-xs text-blue-600 mt-1 block">Insira a alíquota da nota fiscal.</span>
          </div>
        )}

        {method === CalculationMethod.TARGET_MARGIN ? (
          <div className="p-4 bg-indigo-50 rounded-lg border border-indigo-100">
            <label className="block text-sm font-bold text-indigo-900 mb-1">Margem de Lucro Alvo (%)</label>
            <input
              id="targetMargin"
              type="number"
              inputMode="decimal"
              min="0"
              max="100"
              step="1"
              placeholder="0"
              value={inputs.targetMargin}
              onFocus={handleFocus}
              onChange={(e) => handleChange('targetMargin', e.target.value)}
              onKeyDown={(e) => handleKeyDown(e)} 
              className="w-full px-3 py-2 border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-indigo-900 font-semibold bg-white placeholder-indigo-300"
            />
            <span className="text-xs text-indigo-600 mt-1 block">Quanto você quer ganhar sobre a venda bruta.</span>
          </div>
        ) : (
          <div className="p-4 bg-emerald-50 rounded-lg border border-emerald-100">
            <label className="block text-sm font-bold text-emerald-900 mb-1">Preço de Venda Teste (R$)</label>
            <input
              id="testPrice"
              type="number"
              inputMode="decimal"
              min="0"
              step="0.01"
              placeholder="0.00"
              value={inputs.testPrice}
              onFocus={handleFocus}
              onChange={(e) => handleChange('testPrice', e.target.value)}
              onKeyDown={(e) => handleKeyDown(e)}
              className="w-full px-3 py-2 border border-emerald-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-900 font-semibold bg-white placeholder-emerald-300"
            />
             <span className="text-xs text-emerald-600 mt-1 block">O preço que você quer praticar no marketplace.</span>
          </div>
        )}
      </div>

      <div className="mt-8 pt-6 border-t border-gray-100">
        <button
          onClick={handleClear}
          className="w-full flex items-center justify-center space-x-2 py-2.5 border border-gray-200 text-gray-500 rounded-lg hover:bg-gray-50 hover:text-gray-700 hover:border-gray-300 transition-all text-sm font-medium"
        >
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
            <path strokeLinecap="round" strokeLinejoin="round" d="M14.74 9l-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 01-2.244 2.077H8.084a2.25 2.25 0 01-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 00-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 013.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 00-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 00-7.5 0" />
          </svg>
          <span>Limpar Dados</span>
        </button>
      </div>
    </div>
  );
};

export default CalculatorInputs;

import React from 'react';
import { PlatformResult } from '../types';
import { formatCurrency, formatPercent } from '../utils/currency';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface ResultCardProps {
  result: PlatformResult;
  colorTheme: 'orange' | 'black' | 'yellow' | 'blue';
  mlListingType?: 'classic' | 'premium';
  onMlListingTypeChange?: (type: 'classic' | 'premium') => void;
  shopeeListingType?: 'standard' | 'free_shipping';
  onShopeeListingTypeChange?: (type: 'standard' | 'free_shipping') => void;
}

const ResultCard: React.FC<ResultCardProps> = ({ 
  result, 
  colorTheme, 
  mlListingType, 
  onMlListingTypeChange,
  shopeeListingType,
  onShopeeListingTypeChange
}) => {

  const themeClasses = {
    orange: { // Shopee
      border: 'border-orange-200',
      bg: 'bg-white',
      header: 'bg-gradient-to-r from-orange-500 to-red-500',
      text: 'text-orange-600',
      fill: '#f97316'
    },
    black: { // TikTok
      border: 'border-gray-200',
      bg: 'bg-white',
      header: 'bg-gray-900',
      text: 'text-gray-900',
      fill: '#111827'
    },
    yellow: { // Mercado Livre
      border: 'border-yellow-200',
      bg: 'bg-white',
      header: 'bg-yellow-400',
      text: 'text-yellow-700', // Darker text for readability
      fill: '#facc15'
    },
    blue: { // Amazon
      border: 'border-slate-200',
      bg: 'bg-white',
      header: 'bg-slate-800',
      text: 'text-slate-800',
      fill: '#1e293b'
    }
  };

  const currentTheme = themeClasses[colorTheme];

  // Calculate total money paid to the platform
  const totalFees = result.totalVariableCosts + 
                    result.feesBreakdown.fixedFee + 
                    (result.feesBreakdown.tax || 0) + 
                    (result.feesBreakdown.affiliate || 0);

  // Calculate total cost (Product + Oper + All Fees)
  const totalProdOper = result.totalFixedCosts - result.feesBreakdown.fixedFee;
  const totalSaleCost = totalProdOper + totalFees;

  const chartData = [
    { name: 'Custo Fixo (Prod + Oper)', value: totalProdOper, color: '#9CA3AF' },
    { name: 'Taxas & Comissões', value: totalFees, color: '#EF4444' },
    { name: 'Lucro Líquido', value: result.netProfit > 0 ? result.netProfit : 0, color: '#10B981' },
  ];

  // Custom text color for ML header because yellow background is light
  const headerTextColor = colorTheme === 'yellow' ? 'text-gray-900' : 'text-white';

  // Clean platform name for display
  const displayName = result.platformName
    .replace(' (Clássico)', '')
    .replace(' (Premium)', '')
    .replace(' (Sem Frete Grátis)', '')
    .replace(' (Com Frete Grátis)', '');

  return (
    <div className={`rounded-xl shadow-lg overflow-hidden border ${currentTheme.border} ${currentTheme.bg} flex flex-col`}>
      <div className={`${currentTheme.header} ${headerTextColor} p-4 flex justify-between items-center`}>
        <h3 className="font-bold text-lg">{displayName}</h3>
        {result.feesBreakdown.affiliate && result.feesBreakdown.affiliate > 0 ? (
          <span className={`text-xs px-2 py-1 rounded backdrop-blur-sm ${colorTheme === 'yellow' ? 'bg-black/10' : 'bg-white/20'}`}>
             Com Afiliado
          </span>
        ) : null}
      </div>

      <div className="p-6 flex-1 flex flex-col">

        {/* Mercado Livre Toggle Section */}
        {colorTheme === 'yellow' && mlListingType && onMlListingTypeChange && (
            <div className="mb-6">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block">
                   Tipo de Anúncio
                 </label>
                 <div className="flex p-1 bg-yellow-50 border border-yellow-200 rounded-lg shadow-inner">
                    <button
                       onClick={() => onMlListingTypeChange('classic')}
                       className={`flex-1 py-1.5 text-xs font-bold rounded uppercase tracking-wide transition-all ${
                         mlListingType === 'classic'
                           ? 'bg-yellow-400 text-yellow-900 shadow-sm'
                           : 'text-yellow-600 hover:text-yellow-800'
                       }`}
                    >
                      Clássico
                    </button>
                    <button
                       onClick={() => onMlListingTypeChange('premium')}
                       className={`flex-1 py-1.5 text-xs font-bold rounded uppercase tracking-wide transition-all ${
                         mlListingType === 'premium'
                           ? 'bg-yellow-400 text-yellow-900 shadow-sm'
                           : 'text-yellow-600 hover:text-yellow-800'
                       }`}
                    >
                      Premium
                    </button>
                 </div>
                 <p className="text-[10px] text-gray-500 mt-1.5 text-center px-1">
                   {mlListingType === 'classic' 
                     ? 'Exposição alta e duração ilimitada.' 
                     : 'Exposição máxima e parcelamento sem juros.'}
                 </p>
            </div>
        )}

        {/* Shopee Toggle Section */}
        {colorTheme === 'orange' && shopeeListingType && onShopeeListingTypeChange && (
